                    <p className="text-2xl font-bold" data-testid="text-details-completed-jobs">
                      {officeDetails.completedJobs}
                    </p>
                  </div>
                  <div className="border rounded-lg p-4">
                    <p className="text-sm text-muted-foreground">Total Jobs</p>
