    hsl: '220 13% 60%',
    hex: '#8B95A1',
    order: 2
  },
  {
    id: 'in_progress',
    label: 'In Progress',
    hsl: '38 92% 50%',
    hex: '#F59E0B',
    order: 3
  },
  {
    id: 'quality_check',
    label: 'Quality Check',
    hsl: '283 39% 53%',
    hex: '#A855F7',
    order: 4
  },
  {
    id: 'ready_for_pickup',
    label: 'Ready for Pickup',
    hsl: '142 76% 36%',
    hex: '#16A34A',
    order: 5
  },
  {
    id: 'completed',
    label: 'Completed',
    hsl: '262 83% 58%',
    hex: '#8B5CF6',
    order: 6
  },
  {
    id: 'cancelled',
    label: 'Cancelled',
    hsl: '0 84% 60%',
    hex: '#EF4444',
    order: 7
  }
];

// Job Type Default Colors
export const DEFAULT_JOB_TYPE_COLORS: ColorDefinition[] = [
  {
    id: 'contacts',
    label: 'Contacts',
    hsl: '220 13% 60%',
    hex: '#8B95A1',
    order: 1
  },
  {
    id: 'glasses',
    label: 'Glasses',
    hsl: '199 89% 48%',
    hex: '#0EA5E9',
    order: 2
  },
  {
    id: 'sunglasses',
    label: 'Sunglasses',
    hsl: '38 92% 50%',
    hex: '#F59E0B',
    order: 3
  },
  {
    id: 'prescription',
    label: 'Prescription',
    hsl: '283 39% 53%',
    hex: '#A855F7',
    order: 4
  }
];

// Destination Default Colors
export const DEFAULT_DESTINATION_COLORS: ColorDefinition[] = [
  {
    id: 'vision_lab',
    label: 'Vision Lab',
    hsl: '220 60% 88%',
    hex: '#E0E7FF',
    order: 1
  },
  {
    id: 'eyetech_labs',
    label: 'EyeTech Labs',
    hsl: '142 76% 88%',
    hex: '#D1FAE5',
    order: 2
  },
  {
    id: 'premium_optics',
    label: 'Premium Optics',
    hsl: '45 100% 88%',
    hex: '#FEF3C7',
    order: 3
  }
];

// Helper function to get default color by ID
export function getDefaultStatusColor(statusId: string): ColorDefinition | undefined {
  return DEFAULT_STATUS_COLORS.find(c => c.id === statusId);
}

export function getDefaultJobTypeColor(typeId: string): ColorDefinition | undefined {
  return DEFAULT_JOB_TYPE_COLORS.find(c => c.id === typeId);
}

export function getDefaultDestinationColor(destinationLabel: string): ColorDefinition | undefined {
  return DEFAULT_DESTINATION_COLORS.find(c => c.label === destinationLabel);
}

// Helper to convert hex to HSL for display
export function hexToHSL(hex: string): string {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  if (!result) return '0 0% 50%';

  let r = parseInt(result[1], 16) / 255;
  let g = parseInt(result[2], 16) / 255;
  let b = parseInt(result[3], 16) / 255;

  const max = Math.max(r, g, b);
  const min = Math.min(r, g, b);
  let h = 0, s = 0, l = (max + min) / 2;

  if (max !== min) {
    const d = max - min;
    s = l > 0.5 ? d / (2 - max - min) : d / (max + min);
    switch (max) {
      case r: h = ((g - b) / d + (g < b ? 6 : 0)) / 6; break;
      case g: h = ((b - r) / d + 2) / 6; break;
      case b: h = ((r - g) / d + 4) / 6; break;
    }
  }

  h = Math.round(h * 360);
  s = Math.round(s * 100);
  l = Math.round(l * 100);

  return `${h} ${s}% ${l}%`;
}

// Helper to get color for badge styling
export function getColorForBadge(color: string): { background: string; text: string } {
  // If it's already in HSL format (from our defaults)
  if (color.includes('%')) {
    return {
      background: `hsl(${color} / 0.15)`,
      text: `hsl(${color})`
    };
  }

  // If it's hex, convert to HSL and apply
  const hsl = hexToHSL(color);
  return {
    background: `hsl(${hsl} / 0.15)`,
    text: `hsl(${hsl})`
  };
}

client/src/pages/accept-invite.tsx.content:
import { useRoute, Redirect, useLocation } from "wouter";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Loader2, Glasses, Mail, Building2, UserCheck, AlertCircle } from "lucide-react";
import { useAuth } from "@/hooks/use-auth";
import { apiRequest } from "@/lib/queryClient";

const registerSchema = z.object({
  firstName: z.string().min(1, "First name is required"),
  lastName: z.string().min(1, "Last name is required"),
  password: z.string()
    .min(12, "Password must be at least 12 characters")
    .regex(/[A-Z]/, "Password must contain at least one uppercase letter")
    .regex(/[a-z]/, "Password must contain at least one lowercase letter")
    .regex(/[0-9]/, "Password must contain at least one number")
    .regex(/[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/, "Password must contain at least one special character"),
});

type RegisterFormData = z.infer<typeof registerSchema>;

interface InviteData {
  email: string;
  role: string;
  message: string | null;
  officeId: string;
  officeName: string;
  inviterName: string;
}

export default function AcceptInvite() {
  const [match, params] = useRoute("/accept-invite/:token");
  const [, setLocation] = useLocation();
  const { user } = useAuth();
  const token = params?.token;

  const { data: invite, isLoading, error } = useQuery<InviteData>({
    queryKey: ['/api/invitations/verify', token],
    queryFn: async () => {
      const res = await fetch(`/api/invitations/verify/${token}`);
      if (!res.ok) {
        const errorData = await res.json();
        throw new Error(errorData.error || 'Failed to verify invitation');
      }
      return res.json();
    },
    enabled: !!token && !user,
  });

  const registerForm = useForm<RegisterFormData>({
    resolver: zodResolver(registerSchema),
    defaultValues: { firstName: "", lastName: "", password: "" },
  });

  const registerMutation = useMutation({
    mutationFn: async (data: RegisterFormData) => {
      const res = await apiRequest("POST", '/api/register', {
        email: invite?.email,
        firstName: data.firstName,
        lastName: data.lastName,
        password: data.password,
        inviteToken: token,
      });
      return res.json();
    },
    onSuccess: () => {
      setLocation('/');
    },
    onError: (error: Error) => {
      registerForm.setError('root', {
        message: error.message || 'Registration failed',
      });
    },
  });

  if (!match || !token) {
    return <Redirect to="/auth" />;
  }

  if (user) {
    return <Redirect to="/" />;
  }

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen flex items-center justify-center p-8">
        <Card className="w-full max-w-md">
          <CardHeader>
            <div className="flex items-center justify-center w-16 h-16 bg-destructive/10 rounded-xl mb-4 mx-auto">
              <AlertCircle className="h-8 w-8 text-destructive" />
            </div>
            <CardTitle className="text-center">Invalid Invitation</CardTitle>
            <CardDescription className="text-center">
              {(error as Error).message}
            </CardDescription>
          </CardHeader>
          <CardContent>
            <Button
              onClick={() => setLocation('/auth')}
              className="w-full"
              data-testid="button-go-to-auth"
            >
              Go to Sign In
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  if (!invite) {
    return null;
  }

  const onRegister = (data: RegisterFormData) => {
    registerMutation.mutate(data);
  };

  const roleLabel = invite.role.charAt(0).toUpperCase() + invite.role.slice(1).replace('_', ' ');

  return (
    <div className="min-h-screen grid lg:grid-cols-2">
      <div className="flex items-center justify-center p-8">
        <div className="w-full max-w-md space-y-8">
          <div className="text-center">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-primary rounded-xl mb-4">
              <Glasses className="h-8 w-8 text-primary-foreground" />
            </div>
            <h1 className="text-3xl font-bold text-foreground mb-2">Otto Tracker</h1>
            <p className="text-muted-foreground">You've been invited to join a team!</p>
          </div>

          <Card>
            <CardHeader>
              <CardTitle>Team Invitation</CardTitle>
              <CardDescription>
                {invite.inviterName} has invited you to join {invite.officeName}
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              <div className="space-y-3">
                <div className="flex items-center gap-3 p-3 bg-muted/50 rounded-lg">
                  <Building2 className="h-5 w-5 text-primary" />
                  <div>
                    <p className="text-sm font-medium">Office</p>
                    <p className="text-sm text-muted-foreground" data-testid="text-office-name">{invite.officeName}</p>
                  </div>
                </div>

                <div className="flex items-center gap-3 p-3 bg-muted/50 rounded-lg">
                  <UserCheck className="h-5 w-5 text-primary" />
                  <div>
                    <p className="text-sm font-medium">Role</p>
                    <p className="text-sm text-muted-foreground" data-testid="text-role">{roleLabel}</p>
                  </div>
                </div>

                <div className="flex items-center gap-3 p-3 bg-muted/50 rounded-lg">
                  <Mail className="h-5 w-5 text-primary" />
                  <div>
                    <p className="text-sm font-medium">Email</p>
                    <p className="text-sm text-muted-foreground" data-testid="text-email">{invite.email}</p>
                  </div>
                </div>
              </div>

              {invite.message && (
                <Alert>
                  <AlertDescription data-testid="text-message">
                    <span className="font-semibold">Message: </span>
                    {invite.message}
                  </AlertDescription>
                </Alert>
              )}

              <div className="border-t pt-6">
                <h3 className="font-semibold mb-4">Create Your Account</h3>
